final:
module RefModule(
   input                clk,
   input                rst_n,
   output reg [3:0]     Q  
);
    reg [3:0] unused_binary_counter;

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) unused_binary_counter <= 4'd0;
        else unused_binary_counter <= unused_binary_counter + 1;
    end

    always@* begin
        Q = unused_binary_counter ^ (unused_binary_counter >> 1);
    end
endmodule
